28	/*! \brief The manager of internal id for requests in engine. */
29	struct EngineInternalIDManager {
30	  std::vector<int64_t> available_ids;
31	  int64_t id_cnt = 0;
32	
33	  /*! \brief Return an unused id. */
34	  int64_t GetNewId() {
35	    if (!available_ids.empty()) {
36	      int64_t id = available_ids.back();
37	      available_ids.pop_back();
38	      return id;
39	    } else {
40	      return id_cnt++;
41	    }
42	  }
43	
44	  /*! \brief Recycle an id. */
45	  void RecycleId(int64_t id) { available_ids.push_back(id); }
46	
47	  /*! \brief Reset the manager. */
48	  void Reset() {
49	    available_ids.clear();
50	    id_cnt = 0;
51	  }
52	};
