30	/*!
31	 * \brief The state of a request with regard to some single model.
32	 * \details In MLC LLM, the serving engine may leverage multiple models
33	 * to fulfill a user generation request (e.g., use speculation decoding).
34	 * For each request, we isolate its states (e.g. the generated tokens)
35	 * on each model. This is to say, we use RequestModelState to store
36	 * the state of a user request on a single model (rather than all models).
37	 */
38	class RequestModelStateNode : public Object {
39	 public:
40	  /*! \brief The request that this state corresponds to. */
41	  Request request;
42	  /*!
43	   * \brief The internal request id of this state.
44	   * It is the **physical index** of the request in the running request queue.
45	   * If the request is on hold (not in the running queue), the request id
46	   * should be -1.
47	   */
48	  int64_t internal_id = -1;
49	  /*! \brief The corresponding model id of this state. */
50	  int model_id = -1;
51	  /*!
52	   * \brief The committed generated token ids and related probability info.
53	   * A token is "committed" means it will no longer be updated (or changed).
54	   */
55	  std::vector<SampleResult> committed_tokens;
56	  /*! \brief The list of input data yet for the model to prefill. */
57	  Array<Data> inputs;
58	  /*! \brief The list of prefilled input data, used to notify prefix cache. */
59	  std::vector<Data> prefilled_inputs;
60	  /*! \brief The number of tokens already cached in prefix cache. */
61	  int64_t cached_committed_tokens = 0;
62	  /*! \brief The number of tokens that is already prefilled from the inputs. */
63	  int64_t num_prefilled_tokens = 0;
64	  /*! \brief The number of tokens that need to be processed in the next decoding. */
65	  int num_tokens_for_next_decode = 0;
66	  /*! \brief Whether retokenization is needed in the next decoding. When the jump-forward decoding
67	   * is enabled, retokenization is needed after every jump-forward and decoding action. */
68	  bool require_retokenization_in_next_decode = false;
69	
70	  // NOTE: The following fields are reserved for future speculative inference
71	  // settings, and are produced by the speculative small models.
72	  /*!
73	   * \brief The draft generated token ids and related probability info,
74	   * which are usually generated by "small" speculative models.
75	   * These tokens will be fed to a "large" model to determine the final
76	   * result of speculation.
77	   */
78	  std::vector<SampleResult> draft_output_tokens;
79	  /*! \brief The storage slots for the associated states of draft tokens. */
80	  std::vector<int> draft_token_slots;
81	  /*! \brief The parent indices of the draft tokens. */
82	  std::vector<int64_t> draft_token_parent_idx;
83	  /*! \brief The first child indices of the draft tokens. */
84	  std::vector<int64_t> draft_token_first_child_idx;
85	
86	  /*! \brief The appeared committed and draft tokens and their occurrence times. */
87	  std::unordered_map<int32_t, int32_t> appeared_token_ids;
88	
89	  /*!
90	   * \brief The current state of the generated token matching the grammar. Used in grammar-guided
91	   * generation, otherwise it's std::nullopt.
92	   */
93	  std::optional<xgrammar::GrammarMatcher> grammar_matcher;
94	
95	  /*! \brief Return the total length of the input data. */
96	  int GetInputLength() const;
97	  /*!
98	   * \brief Return whether the next token bitmask is required, i.e. the grammar-guided generation is
99	   * enabled.
100	   */
101	  bool RequireNextTokenBitmask();
102	  /*!
103	   * \brief Find the next token bitmask and store it in the given DLTensor.
104	   * \param bitmask The DLTensor to store the next token bitmask. The bitmask should be a tensor
105	   * with dtype uint32_t and shape (ceildiv(vocab_size, 32),).
106	   */
107	  void GetNextTokenBitmask(DLTensor* bitmask);
108	  /*! \brief Commit a new token into committed_tokens. Does not effect the kv cache. Update
109	   * appeared_token_ids and the grammar state. */
110	  void CommitToken(SampleResult sampled_token);
111	  /*! \brief Roll back the last tokens back from committed_tokens. Does not effect the kv cache.
112	   * Also roll back appeared_token_ids and the grammar state. */
113	  void RollbackTokens(int count);
114	
115	  /*! \brief Add a draft token into draft_output_tokens. Update appeared_token_ids. */
116	  void AddDraftToken(SampleResult sampled_token, int draft_token_slot, int64_t parent_idx);
117	  /*! \brief Remove all draft tokens from draft_output_tokens. Update appeared_token_ids. */
118	  void RemoveAllDraftTokens(std::vector<int>* removed_draft_token_slots = nullptr);
119	
120	  static void RegisterReflection() {
121	    namespace refl = tvm::ffi::reflection;
122	    refl::ObjectDef<RequestModelStateNode>();
123	  }
124	
125	  static constexpr const bool _type_has_method_sequal_reduce = false;
126	  static constexpr const bool _type_has_method_shash_reduce = false;
127	  static constexpr const bool _type_mutable = true;
128	  TVM_FFI_DECLARE_OBJECT_INFO("mlc.serve.RequestModelState", RequestModelStateNode, Object);
129	};
