195	 * \brief A request's state entry. It contains the state of a single
196	 * generation of a request, or the state of a prompt prefix of a request.
197	 */
198	class RequestStateEntryNode : public Object {
199	 public:
200	  /*! \brief The status of the request state entry. */
201	  RequestStateStatus status;
202	  /*! \brief The request that this state corresponds to. */
203	  Request request;
204	  /*!
205	   * \brief The idx of the parent request state entry of this state.
206	   * Being -1 means the state has no parent and is the foremost
207	   * "prefix" entry or the only entry.
208	   */
209	  int parent_idx = -1;
210	  /*! \brief The children indices of the request state entry. */
211	  std::vector<int> child_indices;
212	
213	  /*!
214	   * \brief The state with regard to each model.
215	   * \sa RequestModelState
216	   */
217	  Array<RequestModelState> mstates;
218	  /*! \brief The random number generator of this request state entry. */
219	  RandomGenerator rng;
220	  /*! \brief The stop string handler of this request state entry. */
221	  StopStrHandler stop_str_handler;
222	  /*!
223	   * \brief The start position of the committed tokens in the
224	   * next request stream callback invocation.
225	   */
226	  int next_callback_token_pos;
227	
228	  /*! \brief The extra string to prepend the output. */
229	  std::string extra_prefix_string;
230	
231	  std::vector<int32_t> token_ids_for_prefix_cache_update;
232	
233	  /*!
234	   * \brief Back reference to the request state.
235	   * Use ObjectRef to avoid circulate reference.
236	   */
237	  RequestStateNode* rstate = nullptr;
238	
239	  /*!
240	   * \brief Get the delta token ids and the logprob JSON strings for this request to return since
241	   * the last time calling into this function, and return the finish reason if the request
242	   * generation has finished.
243	   * \note This function follows the destination passing style, which means it writes the
244	   * output into the "idx"-th slot in "delta_stream_output".
245	   * We adopt the destination passing style to reduce the CPU data structure allocation and
246	   * construction overhead.
247	   * \param tokenizer The tokenizer for logprob process.
248	   * \param max_single_sequence_length The maximum allowed single sequence length.
249	   * \param delta_stream_output The delta token ids to return, the logprob JSON strings
250	   * of each delta token id, and the optional finish reason.
251	   * \param idx The index denoting which slot to write results in "delta_request_return".
252	   */
253	  void GetDeltaRequestReturn(const Tokenizer& tokenizer, int64_t max_single_sequence_length,
254	                             RequestStreamOutput* delta_stream_output, int idx);
255	
256	  static void RegisterReflection() {
257	    namespace refl = tvm::ffi::reflection;
258	    refl::ObjectDef<RequestStateEntryNode>();
259	  }
260	
261	  static constexpr const bool _type_has_method_sequal_reduce = false;
262	  static constexpr const bool _type_has_method_shash_reduce = false;
263	  static constexpr const bool _type_mutable = true;
264	  TVM_FFI_DECLARE_OBJECT_INFO_FINAL("mlc.serve.RequestStateEntry", RequestStateEntryNode, Object);
265	};
