23	/*!
24	 * \brief The class for tracking mean time cost.
25	 * - We maintain the number of updates (`count`) and the sum of updated values (`sum`).
26	 * - We support warmup. When `warmup` is false, the first update will be discarded.
27	 */
28	struct TimeCost {
29	  /*! \brief the total amount of cost excluding warm up time */
30	  double sum = 0.0;
31	  /*! \brief the total count of events excluding warmup */
32	  int64_t count = 0;
33	  /*! \brief Whether we warmed up already, assuming one hit is enough */
34	  bool warmed_up = false;
35	
36	  /*! \brief Update the metric with given value. */
37	  void Update(double value) {
38	    if (warmed_up) {
39	      sum += value;
40	      count += 1;
41	    } else {
42	      warmed_up = true;
43	    }
44	  }
45	
46	  /*! \brief Reset the metric. */
47	  void Reset() {
48	    // NOTE: no need to redo warmup
49	    // assuming we are measuring the same thing
50	    this->sum = 0.0;
51	    this->count = 0;
52	  }
53	
54	  /*! \brief Dump the metric as JSON. */
55	  tvm::ffi::json::Object AsJSON() const;
56	};
