61	  std::vector<int64_t> draft_count;
62	  /*! \brief The number of accepted tokens in speculative decoding, per step */
63	  std::vector<int64_t> accept_count;
64	
65	  /*!
66	   * \brief Update the metrics of speculative decoding.
67	   * \param draft_length The number of draft tokens (including the last prediction by the base
68	   * model)
69	   * \param accept_length The number of accepted tokens in the speculative decoding.
70	   */
71	  void Update(int draft_length, int accept_length) {
72	    TVM_FFI_ICHECK_GE(accept_length, 1);
