106	void AbortRequestImpl(EngineState estate, const Array<Model>& models, const String& request_id,
107	                      String finish_reason) {
108	  auto it_rstate = estate->request_states.find(request_id);
109	  if (it_rstate == estate->request_states.end()) {
110	    // The request to abort does not exist.
111	    return;
112	  }
113	
114	  RequestState rstate = it_rstate->second;
115	  Request request = rstate->entries[0]->request;
116	
117	  // - Check if the request is running or pending.
118	  auto it_running = std::find(estate->running_queue.begin(), estate->running_queue.end(), request);
119	  auto it_waiting = std::find(estate->waiting_queue.begin(), estate->waiting_queue.end(), request);
120	
121	  estate->request_states.erase(request->id);
122	  if (it_running != estate->running_queue.end()) {
123	    // The request to abort is in running queue
124	    estate->running_queue.erase(it_running);
125	
126	    for (int i = static_cast<int>(rstate->entries.size()) - 1; i >= 0; --i) {
127	      if (estate->prefix_cache->HasSequence(rstate->entries[i]->mstates[0]->internal_id)) {
128	        estate->prefix_cache->RecycleSequence(rstate->entries[i]->mstates[0]->internal_id,
129	                                              /*lazy=*/false);
130	      } else {
131	        if (rstate->entries[i]->status != RequestStateStatus::kAlive) {
132	          estate->id_manager.RecycleId(rstate->entries[i]->mstates[0]->internal_id);
133	          continue;
134	        }
135	        RemoveRequestFromModel(estate, rstate->entries[i]->mstates[0]->internal_id, models);
136	        estate->id_manager.RecycleId(rstate->entries[i]->mstates[0]->internal_id);
137	      }
138	    }
139	  }
140	  if (it_waiting != estate->waiting_queue.end()) {
141	    // The request to abort is in waiting queue
142	    estate->waiting_queue.erase(it_waiting);
143	  }
144	  // Todo: abortion when the request is not in either queue?
145	
146	  // Send a callback to notice the abortion.
147	  StreamBackErrorImpl(request, estate->request_stream_callback_, finish_reason);
148	  estate->running_rsentries_changed = true;
149	}
